    (TrueVal == C1 || FalseVal == C2)) {
  // We can swap the operands of the fcmp and the select.
  // TODO: This is not valid for NNAN/NSZ.
  FCmpInst::Predicate InvPred = FCmpInst::getInversePredicate(Pred);
  Value *NewFCmp = Builder.CreateFCmp(InvPred, X, Y);
  return SelectInst::Create(NewFCmp, FalseVal, TrueVal);
}
```
The `TODO` comment confirms my suspicion: "This is not valid for NNAN/NSZ."
The fix is to disable this transformation if the `select` has `nnan` or `nsz` flags.

I will add a check for these flags before performing the transformation.
```cpp
// select (fcmp C, X, Y), C1, C2 -> select (fcmp C, Y, X), C2, C1
if (match(C, m_FCmp(Pred, m_Value(X), m_Value(Y))) &&
    (TrueVal == C1 || FalseVal == C2)) {
  // We can swap the operands of the fcmp and the select.
  if (SI.hasNoNaNs() || SI.hasNoSignedZeros()) // This is not valid for NNAN/NSZ.
    return nullptr;
  FCmpInst::Predicate InvPred = FCmpInst::getInversePredicate(Pred);
  Value *NewFCmp = Builder.CreateFCmp(InvPred, X, Y);
  return SelectInst::Create(NewFCmp, FalseVal, TrueVal);
}
```
This seems correct. I will now apply this change using `sed`.

```bash
sed -i "s|// TODO: This is not valid for NNAN/NSZ.|if (SI.hasNoNaNs() || SI.hasNoSignedZeros()) return nullptr; // This is not valid for NNAN/NSZ.|" lib/Transforms/InstCombine/InstCombineSelect.cpp
```

